mapper.select:
SELECT * FROM sensor_data
WHERE device_id = #{deviceId}

    AND type = #{type}


    AND recorded_at >= #{startTime}


    AND recorded_at <= #{endTime}

ORDER BY recorded_at ASC

    LIMIT #{limit}

SELECT s1.* FROM sensor_data s1
                     INNER JOIN (
    SELECT type, MAX(recorded_at) AS max_time
    FROM sensor_data
    WHERE device_id = #{deviceId}
    GROUP BY type
) s2 ON s1.type = s2.type AND s1.recorded_at = s2.max_time
WHERE s1.device_id = #{deviceId}
